export default AnalysisView;

import React, { useState } from 'react';
import ReactMarkdown from 'react-markdown';
import { Copy, CheckCircle, RefreshCw, PenTool } from './Icons';

interface ArticleViewProps {
  content: string;
  onReset: () => void;
}

const ArticleView: React.FC<ArticleViewProps> = ({ content, onReset }) => {
  const [copied, setCopied] = useState(false);

  const handleCopy = () => {
    navigator.clipboard.writeText(content);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="animate-fade-in">
      <div className="bg-white rounded-xl shadow-lg border border-slate-200 overflow-hidden">
        {/* Toolbar */}
        <div className="p-4 border-b border-slate-100 bg-white sticky top-0 z-10 flex justify-between items-center shadow-sm">
          <div className="flex items-center gap-2 text-slate-800 font-semibold">
            <PenTool className="w-5 h-5 text-green-600" />
            <span>Final Article</span>
          </div>
          <div className="flex items-center gap-3">
            <button
              onClick={handleCopy}
              className={`flex items-center gap-1.5 px-3 py-1.5 rounded-md text-sm font-medium transition-colors border
                ${copied 
                  ? 'bg-green-50 text-green-700 border-green-200' 
                  : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50'}`}
            >
              {copied ? <CheckCircle className="w-4 h-4" /> : <Copy className="w-4 h-4" />}
              {copied ? 'Copied' : 'Copy Text'}
            </button>
            <button
              onClick={onReset}
              className="flex items-center gap-1.5 px-3 py-1.5 rounded-md text-sm font-medium text-slate-600 hover:text-slate-800 transition-colors"
            >
              <RefreshCw className="w-4 h-4" />
              Start New
            </button>
          </div>
        </div>

        {/* Content */}
        <div className="p-8 lg:p-12 prose prose-slate max-w-none prose-lg prose-headings:font-bold prose-h1:text-3xl prose-h2:text-2xl prose-a:text-blue-600 prose-img:rounded-xl">
          <ReactMarkdown>{content}</ReactMarkdown>
        </div>
      </div>

      <div className="text-center mt-8 pb-8">
         <p className="text-slate-400 text-sm">Generated content should be reviewed for accuracy before publishing.</p>
      </div>
    </div>
  );
};

export default ArticleView;

import React, { useState } from 'react';
import InputForm from './components/InputForm';
import AnalysisView from './components/AnalysisView';
import ArticleView from './components/ArticleView';
import { AppState, FormData, AnalysisData } from './types';
import { analyzeKeyword, generateArticle } from './services/geminiService';
import { Loader2 } from './components/Icons';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.IDLE);
  const [formData, setFormData] = useState<FormData>({
    keyword: '',
    language: 'English',
    wordCount: 1000,
    customContext: ''
  });
  const [analysisData, setAnalysisData] = useState<AnalysisData | null>(null);
  const [articleContent, setArticleContent] = useState<string>('');
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  const handleAnalysisSubmit = async () => {
    setAppState(AppState.ANALYZING);
    setErrorMsg(null);
    try {
      const data = await analyzeKeyword(formData);
      setAnalysisData(data);
      setAppState(AppState.REVIEW);
    } catch (err: any) {
      setErrorMsg(err.message || "An unexpected error occurred during analysis.");
      setAppState(AppState.IDLE);
    }
  };

  const handleGenerateArticle = async () => {
    if (!analysisData) return;
    setAppState(AppState.GENERATING);
    try {
      const content = await generateArticle(formData, analysisData);
      setArticleContent(content);
      setAppState(AppState.COMPLETE);
    } catch (err: any) {
      setErrorMsg(err.message || "Failed to generate article.");
      setAppState(AppState.REVIEW);
    }
  };

  const handleReset = () => {
    setAppState(AppState.IDLE);
    setAnalysisData(null);
    setArticleContent('');
    setErrorMsg(null);
    setFormData(prev => ({ ...prev, keyword: '', customContext: '' }));
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans text-slate-900">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-50">
        <div className="max-w-6xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white font-bold text-lg shadow-sm">
              S
            </div>
            <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-700 to-indigo-600">
              SEO Master AI
            </h1>
          </div>
          <div className="text-xs font-medium px-2 py-1 bg-green-100 text-green-700 rounded border border-green-200">
            Powered by Gemini
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-6xl mx-auto px-4 py-8">

        {/* Error Notification */}
        {errorMsg && (
          <div className="mb-6 p-4 bg-red-50 border border-red-200 rounded-lg text-red-700 text-sm flex items-center gap-2">
            <span className="font-bold">Error:</span> {errorMsg}
          </div>
        )}

        {/* State: IDLE or ANALYZING (Show Form) */}
        {(appState === AppState.IDLE || appState === AppState.ANALYZING) && (
          <div className="max-w-2xl mx-auto animate-fade-in-up">
            <div className="text-center mb-10">
              <h2 className="text-3xl font-bold text-slate-900 mb-3">Create Top-Ranking Content</h2>
              <p className="text-slate-500">
                Analyze competition, extract keywords, and generate E-E-A-T optimized articles in seconds.
              </p>
            </div>
            <InputForm 
              formData={formData} 
              setFormData={setFormData} 
              onSubmit={handleAnalysisSubmit}
              isLoading={appState === AppState.ANALYZING}
            />
            {appState === AppState.ANALYZING && (
              <div className="mt-8 text-center text-slate-500 flex flex-col items-center gap-3 animate-pulse">
                <Loader2 className="w-8 h-8 text-blue-600 animate-spin" />
                <p>Scanning search results and analyzing keyword difficulty...</p>
              </div>
            )}
          </div>
        )}

        {/* State: REVIEW or GENERATING (Show Analysis Dashboard) */}
        {(appState === AppState.REVIEW || appState === AppState.GENERATING) && analysisData && (
          <div className="space-y-6">
            <div className="flex items-center justify-between mb-4">
               <h2 className="text-2xl font-bold text-slate-800">Strategy Report: <span className="text-blue-600">{formData.keyword}</span></h2>
               <button onClick={handleReset} className="text-sm text-slate-500 hover:text-slate-800 underline">Start Over</button>
            </div>
            <AnalysisView 
              data={analysisData} 
              onGenerate={handleGenerateArticle}
              isGenerating={appState === AppState.GENERATING}
            />
          </div>
        )}

        {/* State: COMPLETE (Show Final Article) */}
        {appState === AppState.COMPLETE && (
          <ArticleView content={articleContent} onReset={handleReset} />
        )}

      </main>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisData, FormData, GroundingSource } from "../types";

// Initialize Gemini Client
// Using process.env.API_KEY as strictly required
const getClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Analyzes the keyword using Gemini with Google Search Grounding.
 * Uses gemini-2.5-flash for speed and tool support.
 */
export const analyzeKeyword = async (formData: FormData): Promise<AnalysisData> => {
  const client = getClient();

  const prompt = `
    Perform a comprehensive SEO analysis for the keyword: "${formData.keyword}" in language: "${formData.language}".

    1. Estimate the Keyword Difficulty (Low, Medium, or High) based on the likely competition found in search results. Explain why in one sentence.
    2. List 8-10 semantically related keywords or long-tail variations that should be included in the content.
    3. Identify 3-5 key topics or angles that top-ranking pages are covering.
    4. Create a detailed article outline (H1, H2, H3 structure) that follows E-E-A-T principles.

    IMPORTANT: Return the result as a valid JSON object. Do not include any introductory text or explanations outside the JSON.

    The JSON structure must be:
    {
